const sitemaps = $input.first().json.sitemapindex?.sitemap || [];
const sitemapArray = Array.isArray(sitemaps) ? sitemaps : [sitemaps];

return sitemapArray.map(s => ({
  json: { loc: typeof s.loc === 'string' ? s.loc : (s.loc._text || s.loc['#text'] || '') }
})).filter(item => item.json.loc);

const SKIP_LIST = [
  "/wp-", "/wp-content", "/wp-admin", "/cdn-cgi",
  ".png", ".jpg", ".jpeg", ".gif", ".svg", ".webp",
  ".pdf", ".css", ".js", ".xml", ".ico", ".woff",
  "google.com", "facebook.com", "shortpixel"
];

function stripTags(html) {
  let result = "";
  let inside = false;
  for (const ch of html) {
    if (ch === "<") inside = true;
    else if (ch === ">") inside = false;
    else if (!inside) result += ch;
  }
  return result;
}

function decodeEntities(text) {
  return text
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&nbsp;/g, " ")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&ndash;/g, "-")
    .replace(/&mdash;/g, "-")
    .replace(/&#8211;/g, "-")
    .replace(/&#8212;/g, "-")
    .replace(/&#8216;/g, "'")
    .replace(/&#8217;/g, "'")
    .replace(/&#8220;/g, '"')
    .replace(/&#8221;/g, '"');
}

function collapseSpace(text) {
  let t = text;
  while (t.includes("  ")) t = t.replace(/  /g, " ");
  while (t.includes("\n\n\n")) t = t.replace(/\n\n\n/g, "\n\n");
  return t.trim();
}

function extractBetween(html, openTag, closeTag) {
  const results = [];
  const lower = html.toLowerCase();
  const openL = openTag.toLowerCase();
  const closeL = closeTag.toLowerCase();
  let pos = 0;
  const length = html.length;

  while (pos < length) {
    const start = lower.indexOf(openL, pos);
    if (start === -1) break;
    const tagEnd = lower.indexOf(">", start);
    if (tagEnd === -1) break;
    const contentStart = tagEnd + 1;
    const end = lower.indexOf(closeL, contentStart);
    if (end === -1) break;
    results.push(html.slice(contentStart, end));
    pos = end + closeL.length;
  }
  return results;
}

function removeTagBlocks(html, tag) {
  const openT = "<" + tag;
  const closeT = "</" + tag + ">";
  const lower = html.toLowerCase();
  let result = "";
  let pos = 0;
  const length = html.length;

  while (pos < length) {
    const idx = lower.indexOf(openT, pos);
    if (idx === -1) {
      result += html.slice(pos);
      break;
    }
    result += html.slice(pos, idx);
    const end = lower.indexOf(closeT, idx);
    if (end === -1) break;
    pos = end + closeT.length;
  }
  return result;
}

function extractMeta(html, name) {
  const lower = html.toLowerCase();
  let needle = `name="${name}"`;
  let idx = lower.indexOf(needle);
  if (idx === -1) {
    needle = `name='${name}'`;
    idx = lower.indexOf(needle);
  }
  if (idx === -1) return "";

  const blockStart = lower.lastIndexOf("<meta", idx);
  if (blockStart === -1) return "";
  const blockEnd = lower.indexOf(">", blockStart);
  if (blockEnd === -1) return "";

  const block = html.slice(blockStart, blockEnd);
  const lowerBlock = block.toLowerCase();

  for (const q of ['"', "'"]) {
    const key = "content=" + q;
    const ci = lowerBlock.indexOf(key);
    if (ci !== -1) {
      const start = ci + key.length;
      const end = block.indexOf(q, start);
      if (end !== -1) return block.slice(start, end).trim();
    }
  }
  return "";
}

function extractOg(html, propertyName) {
  const lower = html.toLowerCase();
  let needle = `property="og:${propertyName}"`;
  let idx = lower.indexOf(needle);
  if (idx === -1) {
    needle = `property='og:${propertyName}'`;
    idx = lower.indexOf(needle);
  }
  if (idx === -1) return "";

  const blockStart = lower.lastIndexOf("<meta", idx);
  if (blockStart === -1) return "";
  const blockEnd = lower.indexOf(">", blockStart);
  if (blockEnd === -1) return "";

  const block = html.slice(blockStart, blockEnd);
  const lowerBlock = block.toLowerCase();

  for (const q of ['"', "'"]) {
    const key = "content=" + q;
    const ci = lowerBlock.indexOf(key);
    if (ci !== -1) {
      const start = ci + key.length;
      const end = block.indexOf(q, start);
      if (end !== -1) return block.slice(start, end).trim();
    }
  }
  return "";
}

function cleanText(raw) {
  let text = stripTags(raw);
  text = decodeEntities(text);
  text = collapseSpace(text);
  return text;
}

const result = [];

for (const item of $input.all()) {
  let html = item.json.data || "";
  const url = item.json.url || "";
  const section = item.json.section || "";

  if (html.length < 200) continue;

  for (const tag of ["script", "style", "nav", "footer", "header", "noscript", "iframe", "svg", "button", "form"]) {
    html = removeTagBlocks(html, tag);
  }

  // Title
  let titleRaw = "";
  const lowerHtml = html.toLowerCase();
  const tStart = lowerHtml.indexOf("<title");
  if (tStart !== -1) {
    const tEnd = lowerHtml.indexOf("</title>", tStart);
    if (tEnd !== -1) {
      const tagClose = html.indexOf(">", tStart);
      titleRaw = html.slice(tagClose + 1, tEnd);
    }
  }
  let title = cleanText(titleRaw);
  if (title.includes(" | ")) title = title.slice(0, title.indexOf(" | ")).trim();
  if (title.includes(" - ")) title = title.slice(0, title.indexOf(" - ")).trim();

  // Description
  let description = extractMeta(html, "description");
  if (!description) description = extractOg(html, "description");
  description = decodeEntities(description);

  // Author
  let author = extractMeta(html, "author");
  if (!author) author = "Content Team";

  // OG Image
  const ogImage = extractOg(html, "image");

  // Headings
  let headings = [];
  for (const tag of ["h1", "h2", "h3"]) {
    const chunks = extractBetween(html, "<" + tag, "</" + tag + ">");
    for (const chunk of chunks.slice(0, 6)) {
      const h = cleanText(chunk);
      if (h && h.length > 3 && h.length < 200) headings.push(h);
    }
  }
  headings = headings.slice(0, 10);

  // Paragraphs
  const paraChunks = extractBetween(html, "<p", "</p>");
  let paragraphs = [];
  for (const chunk of paraChunks) {
    const p = cleanText(chunk);
    if (p.length > 40) paragraphs.push(p);
  }
  paragraphs = paragraphs.slice(0, 20);

  // List items
  const liChunks = extractBetween(html, "<li", "</li>");
  let listItems = [];
  for (const chunk of liChunks) {
    const li = cleanText(chunk);
    if (li.length > 15 && li.length < 300) listItems.push("- " + li);
  }
  listItems = listItems.slice(0, 20);

  // Build full text
  const parts = [];
  if (title) parts.push("PAGE: " + title);
  if (description) parts.push("DESCRIPTION: " + description);
  if (headings.length) parts.push("HEADINGS: " + headings.join(" | "));
  if (paragraphs.length) parts.push("CONTENT: " + paragraphs.join(" "));
  if (listItems.length) parts.push("POINTS: " + listItems.join(" "));

  let fullText = parts.join(" ");
  fullText = fullText.slice(0, 5000);

  if (fullText.length < 100) continue;

  result.push({
    json: {
      url,
      title,
      author,
      description,
      og_image: ogImage,
      section,
      headings: headings.slice(0, 5).join(" | "),
      text: fullText,
      char_count: fullText.length
    }
  });
}

return result;

// Builds a fully escaped GPT-4o request body using JSON.stringify.
// Also carries all page metadata forward so the Parse FAQs node can access it.

const items_out = [];

for (const item of $input.all()) {
  const url         = item.json.url         || '';
  const title       = item.json.title       || '';
  const author      = item.json.author      || 'Content Team';
  const section     = item.json.section     || '';
  const description = item.json.description || '';
  const headings    = item.json.headings    || '';
  const text        = item.json.text        || '';
  const og_image    = item.json.og_image    || '';

  const headingCount = headings ? headings.split('|').length : 0;

  const systemPrompt = `You are a professional FAQ generator. Your goal is to help website visitors quickly find answers to any question they might have after reading a page.

TASK: Given the content of ONE webpage, generate a COMPLETE set of FAQs covering EVERY distinct section, heading, feature, benefit, statistic, and concept mentioned — so that a visitor's question on ANY part of this page can be answered.

RULES:
1. Coverage: For EACH major heading/section, generate AT LEAST ONE FAQ capturing its core point. Generate separate FAQs for distinct facts within the same section. No upper limit — generate as many as needed for full coverage.
2. No repetition: Each FAQ must cover a DIFFERENT point. No two FAQs should overlap in topic or answer.
3. Specificity: Every question must be answerable using ONLY the provided content.
4. Topic tag: Include a "topic" field — a short 2–5 word category label matching the section it came from.
5. Answers: 2–4 sentences, factual, based only on the given content. No hallucination.
6. Author field: Always include an "author" field copied exactly from the input Author value.
7. Low-content pages: If the page has very little real content (contact page, legal page), return [].
8. Output: Return ONLY a valid JSON array. No preamble, no markdown, no code fences.

Output format: [{"question": "...", "answer": "...", "topic": "...", "author": "..."}, ...]
If no good FAQs can be generated, return: []`;

  const userPrompt = 'Page URL: ' + url + '\nPage Title: ' + title + '\nSection: ' + section + '\nAuthor: ' + author + '\nMeta Description: ' + description + '\nKey Headings (' + headingCount + ' total): ' + headings + '\n\n--- Page Content ---\n' + text + '\n--- End Content ---\n\nThis page has ' + headingCount + ' major headings/sections. Generate FAQs covering ALL of them plus the intro/conclusion, with no duplicate or overlapping questions. Include "author": "' + author + '" in every FAQ object. Return as a JSON array with question, answer, topic, and author fields. Return [] only if the page has no substantive content:';

  const gpt_body = JSON.stringify({
    model: 'gpt-4o',
    max_tokens: 4096,
    temperature: 0.2,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user',   content: userPrompt   }
    ]
  });

  items_out.push({
    json: {
      url, title, author, section, description, headings, og_image,
      heading_count: headingCount,
      gpt_body
    }
  });
}

return items_out;

// Parses the GPT-4o response and builds individual FAQ chunk items.
// Retrieves page metadata from the paired upstream node (🔧 Build GPT Request).

function findJsonArray(text) {
  const start = text.indexOf('[');
  const end   = text.lastIndexOf(']');
  if (start === -1 || end === -1 || end <= start) return '';
  return text.slice(start, end + 1);
}

function makeChunkId(url, index) {
  let slug = url
    .replace(/https?:\/\//, '')
    .replace(/www\./, '')
    .replace(/[^a-zA-Z0-9]/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 70);
  return slug + '__faq_' + String(index).padStart(2, '0');
}

const items_out = [];

for (const item of $input.all()) {

  const choices = item.json.choices || [];
  if (!choices.length) continue;

  const raw = (choices[0]?.message?.content || '').trim();
  if (!raw) continue;

  // Get metadata from the paired upstream node
  const meta = $('Build GPT Request').item.json;

  const arrayStr = findJsonArray(raw);
  if (!arrayStr) continue;

  let faqs = [];
  try {
    faqs = JSON.parse(arrayStr);
  } catch(e) {
    continue;
  }

  if (!Array.isArray(faqs)) continue;

  for (let i = 0; i < faqs.length; i++) {
    const q = (faqs[i].question || '').trim();
    const a = (faqs[i].answer   || '').trim();

    if (!q || !a || q.length < 10 || a.length < 10) continue;

    items_out.push({
      json: {
        chunk_id   : makeChunkId(meta.url, i),
        chunk_text : 'Q: ' + q + ' A: ' + a,
        question   : q,
        answer     : a,
        url        : meta.url,
        title      : meta.title,
        author     : meta.author,
        section    : meta.section,
        og_image   : meta.og_image,
        faq_index  : i
      }
    });
  }
}

return items_out;

const skipList = [
    "/wp-", "/wp-content", "/wp-admin", "/cdn-cgi",
    ".png", ".jpg", ".jpeg", ".gif", ".svg", ".webp",
    ".pdf", ".css", ".js", ".xml", ".ico", ".woff",
    "google.com", "facebook.com", "shortpixel"
];

let allUrls = [];

// Gather all URLs from all sub-sitemaps
for (const item of $input.all()) {
    const urls = item.json?.urlset?.url || [];
    const urlArray = Array.isArray(urls) ? urls : [urls];

    for (const u of urlArray) {
        if (!u || !u.loc) continue;
        const locString = typeof u.loc === 'string' ? u.loc : (u.loc._text || u.loc['#text'] || '');
        if (locString) allUrls.push(locString);
    }
}

// Filter out asset/admin URLs and deduplicate
const cleanUrls = [...new Set(allUrls)].filter(url => {
    const lowerUrl = url.toLowerCase();
    return !skipList.some(skip => lowerUrl.includes(skip));
});

// Output as individual items for the Loop node
return cleanUrls.map(url => ({ json: { loc: url } }));
